def gen(rng, size):
    n = max(1, min(size, 10000))
    nums = []
    for _ in range(n):
        length = rng.randint(1, 100)
        if length == 1:
            nums.append(str(rng.randint(0, 9)))
        else:
            first = str(rng.randint(1, 9))
            rest = ''.join(str(rng.randint(0, 9)) for _ in range(length - 1))
            nums.append(first + rest)
    k = rng.randint(1, n)
    return [nums, k]

