var kthLargestNumber = function(nums, k) {
    const ordered = nums.slice().sort((a, b) => {
        if (a.length !== b.length) return b.length - a.length;
        if (a > b) return -1;
        if (a < b) return 1;
        return 0;
    });
    return ordered[k - 1];
};
